// ── ORCHESTRATION ROUTER ─────────────────────────────────────
// Runs every minute. Decides which flows to activate.

const now       = new Date();
const day       = now.getDay();    // 0=Sun, 1=Mon
const date      = now.getDate();   // 1-31
const hour      = now.getHours();
const minute    = now.getMinutes();

// FLOW 1 — Onboarding: always check for new sheet rows
const runOnboarding = true;

// FLOW 2 — Weekly Pulse: Monday at 08:00 only
const runWeeklyPulse = (day === 1 && hour === 8 && minute === 0);

// FLOW 3 — Reassessment: 1st of month at 09:00 only
const runReassessment = (date === 1 && hour === 9 && minute === 0);

return [{
  json: {
    runOnboarding,
    runWeeklyPulse,
    runReassessment,
    timestamp: now.toISOString()
  }
}];

// ── FLOW 1: AHAM Scoring + Email Builder ─────────────────────
// Filters only unprocessed rows, scores each, builds email HTML

const PROFILES = {
  Conservative: {
    cagrLabel: '10–12%', cagrMid: 0.11, volatility: 'Low',
    color: '#0d9488', description: 'capital preservation with steady income',
    assets: [
      { name: 'NIFTY 50',        pct: 30, type: 'Domestic Equity', color: '#b8860b' },
      { name: 'Corporate Bonds', pct: 33, type: 'Fixed Income',    color: '#0d9488' },
      { name: 'Gold BEES ETF',   pct: 15, type: 'Gold Hedge',      color: '#d97706' },
      { name: 'NIFTY Realty',    pct:  5, type: 'Sectoral',        color: '#7c3aed' },
      { name: 'NIFTY Smallcap',  pct:  7, type: 'Domestic Equity', color: '#ea580c' },
      { name: 'NASDAQ-100 ETF',  pct: 10, type: 'Global Equity',   color: '#2563eb' }
    ]
  },
  Moderate: {
    cagrLabel: '12–18%', cagrMid: 0.15, volatility: 'Moderate',
    color: '#b8860b', description: 'balanced growth with managed risk',
    assets: [
      { name: 'NIFTY 50',        pct: 40, type: 'Domestic Equity', color: '#b8860b' },
      { name: 'Corporate Bonds', pct: 20, type: 'Fixed Income',    color: '#0d9488' },
      { name: 'Gold BEES ETF',   pct:  8, type: 'Gold Hedge',      color: '#d97706' },
      { name: 'NIFTY Realty',    pct:  7, type: 'Sectoral',        color: '#7c3aed' },
      { name: 'NIFTY Smallcap',  pct: 15, type: 'Domestic Equity', color: '#ea580c' },
      { name: 'NASDAQ-100 ETF',  pct: 10, type: 'Global Equity',   color: '#2563eb' }
    ]
  },
  Aggressive: {
    cagrLabel: '19–25%', cagrMid: 0.22, volatility: 'High',
    color: '#dc2626', description: 'maximum long-term wealth creation',
    assets: [
      { name: 'NIFTY 50',        pct: 35, type: 'Domestic Equity', color: '#b8860b' },
      { name: 'Corporate Bonds', pct: 10, type: 'Fixed Income',    color: '#0d9488' },
      { name: 'Gold BEES ETF',   pct:  5, type: 'Gold Hedge',      color: '#d97706' },
      { name: 'NIFTY Realty',    pct: 12, type: 'Sectoral',        color: '#7c3aed' },
      { name: 'NIFTY Smallcap',  pct: 20, type: 'Domestic Equity', color: '#ea580c' },
      { name: 'NASDAQ-100 ETF',  pct: 18, type: 'Global Equity',   color: '#2563eb' }
    ]
  }
};

function scoreVal(v) {
  if (!v) return 2;
  v = v.toString().toLowerCase().trim();
  if (v === 'low')    return 1;
  if (v === 'medium') return 2;
  return 3;
}

function fmtINR(n) {
  if (!n || isNaN(n)) return '₹0';
  if (n >= 10000000) return '₹' + (n/10000000).toFixed(2) + ' Cr';
  if (n >= 100000)   return '₹' + (n/100000).toFixed(2)   + ' L';
  return '₹' + Math.round(n).toLocaleString('en-IN');
}

const results = [];

for (const item of items) {
  const d = item.json;

  // Skip already processed rows
  if (!d['Email']) continue;
  if ((d['Processed'] || '').toString().toUpperCase() === 'TRUE') continue;

  const total =
    scoreVal(d['Horizon'])    +
    scoreVal(d['Income'])     +
    scoreVal(d['Wealth'])     +
    scoreVal(d['Reaction'])   +
    scoreVal(d['Experience']) +
    scoreVal(d['Goal'])       +
    scoreVal(d['Returns']);

  let profile = 'Moderate';
  if (total <= 11) profile = 'Conservative';
  else if (total >= 17) profile = 'Aggressive';

  const p      = PROFILES[profile];
  const invest = parseFloat(d['Investment']) || 100000;
  const years  = parseInt(d['Target Years']) || 10;

  const projMed = invest * Math.pow(1 + p.cagrMid, years);
  const projBst = projMed * 1.45;
  const projWst = projMed * 0.62;

  // QuickChart donut
  const chartConfig = {
    type: 'doughnut',
    data: {
      labels: p.assets.map(a => a.name + ' ' + a.pct + '%'),
      datasets: [{
        data: p.assets.map(a => a.pct),
        backgroundColor: p.assets.map(a => a.color),
        borderWidth: 2, borderColor: '#1a1f2e'
      }]
    },
    options: {
      plugins: {
        legend: { position: 'right', labels: { color: '#f0ede8', font: { size: 11 }, padding: 12 } },
        title:  { display: true, text: profile + ' Portfolio · AHAM', color: '#b8860b', font: { size: 13 } }
      },
      cutout: '62%'
    }
  };
  const chartUrl = 'https://quickchart.io/chart?backgroundColor=%231a1f2e&width=520&height=300&c='
    + encodeURIComponent(JSON.stringify(chartConfig));

  // Score gauge bar
  const scorePct = Math.round(((total - 7) / 14) * 100);
  const scoreGauge = `<div style="background:#212736;border-radius:99px;height:8px;overflow:hidden;margin:10px 0 6px;"><div style="height:100%;width:${scorePct}%;background:linear-gradient(90deg,#0d9488,${p.color});border-radius:99px;"></div></div><div style="display:flex;justify-content:space-between;font-size:10px;color:#5a6480;"><span>Conservative</span><span>Moderate</span><span>Aggressive</span></div>`;

  // Asset table rows
  const assetRows = p.assets.map(a =>
    `<tr><td style="padding:10px 16px;border-bottom:1px solid #2a3144;"><div style="display:flex;align-items:center;gap:8px;"><div style="width:8px;height:8px;border-radius:50%;background:${a.color};flex-shrink:0;"></div><span style="color:#f0ede8;font-size:13px;">${a.name}</span></div></td><td style="padding:10px 16px;border-bottom:1px solid #2a3144;"><span style="background:#181c29;border:1px solid #2a3144;border-radius:4px;padding:2px 8px;font-size:11px;color:#5a6480;">${a.type}</span></td><td style="padding:10px 16px;border-bottom:1px solid #2a3144;text-align:right;"><span style="font-family:monospace;font-size:14px;color:${a.color};font-weight:600;">${a.pct}%</span></td></tr>`
  ).join('');

  const submitDate = new Date().toLocaleDateString('en-IN', { day:'numeric', month:'long', year:'numeric' });

  results.push({
    json: {
      flowType: 'onboarding',
      name: d['Name'], email: d['Email'],
      riskScore: total, riskProfile: profile,
      profileColor: p.color, description: p.description,
      cagrLabel: p.cagrLabel, volatility: p.volatility,
      invest, years,
      projMed: fmtINR(projMed),
      projBst: fmtINR(projBst),
      projWst: fmtINR(projWst),
      investFmt: fmtINR(invest),
      chartUrl, assetRows, scoreGauge, submitDate
    }
  });
}

if (results.length === 0) return [{ json: { flowType: 'onboarding', skip: true } }];
return results;

// ── FLOW 2: Parse market data + build personalised pulses ────

function getPrice(data) {
  if (!data) return null;
  const closes = data?.chart?.result?.[0]?.indicators?.quote?.[0]?.close;
  if (!closes) return null;
  const valid = closes.filter(p => p !== null && p !== undefined);
  return { current: valid[valid.length-1], prev: valid[valid.length-6] || valid[0] };
}

function calcChange(c, p) {
  if (!c || !p) return { pct:'0.00', color:'#b8860b', arrow:'→', sign:'' };
  const pct = ((c - p) / p) * 100;
  return {
    pct:   Math.abs(pct).toFixed(2),
    color: pct > 0.5 ? '#0d9488' : pct < -0.5 ? '#dc2626' : '#b8860b',
    arrow: pct > 0.5 ? '↑' : pct < -0.5 ? '↓' : '→',
    sign:  pct > 0 ? '+' : pct < 0 ? '-' : ''
  };
}

function fmtINR(n) {
  if (!n) return 'N/A';
  return '₹' + Math.round(n).toLocaleString('en-IN');
}

const nifty  = getPrice(items[0]?.json);
const gold   = getPrice(items[1]?.json);
const nasdaq = getPrice(items[2]?.json);

const nC = calcChange(nifty?.current,  nifty?.prev);
const gC = calcChange(gold?.current,   gold?.prev);
const nqC= calcChange(nasdaq?.current, nasdaq?.prev);

// Convert gold & NASDAQ to INR approx (1 USD ~ 83 INR)
const USD_INR = 83;

const weekDate = new Date().toLocaleDateString('en-IN', {
  day:'numeric', month:'long', year:'numeric'
});

const commentary = {
  Conservative: {
    up:   'Your equity allocation (30%) is benefiting from this week\'s rally. Your bond and gold holdings remain stable.',
    down: 'Your defensive allocation — 33% bonds + 15% gold — is cushioning the market dip effectively.',
    flat: 'Markets are consolidating. Your conservative mix is well-positioned for stability.'
  },
  Moderate: {
    up:   'Your 40% NIFTY allocation is working in your favour this week. Smallcap (15%) also trending positive.',
    down: 'A dip week for equity. Your 20% bond allocation is providing a meaningful buffer.',
    flat: 'Quiet week. Your diversified AHAM allocation is balanced for the next market move.'
  },
  Aggressive: {
    up:   'Strong week — your 35% NIFTY + 20% Smallcap + 18% NASDAQ exposure is all performing positively.',
    down: 'Volatility this week. Short-term fluctuations are normal for your aggressive profile — stay the course.',
    flat: 'Markets pausing. Your high-equity positioning is set for the next momentum move.'
  }
};

const niftyDir = parseFloat(nC.pct) > 0.5 && nC.arrow==='↑' ? 'up'
               : parseFloat(nC.pct) > 0.5 && nC.arrow==='↓' ? 'down' : 'flat';

return [{
  json: {
    flowType: 'weeklyPulse',
    weekDate,
    niftyPrice:  fmtINR(nifty?.current),
    niftyChange: nC,
    goldPrice:   fmtINR((gold?.current || 0) * USD_INR),
    goldChange:  gC,
    nasdaqPrice: fmtINR((nasdaq?.current || 0) * USD_INR),
    nasdaqChange:nqC,
    niftyDir,
    commentary
  }
}];

// ── Build personalised weekly pulse per client ───────────────
const results = [];

for (const item of items) {
  const d        = item.json;
  const email    = d['Email']        || '';
  const name     = d['Name']         || 'Investor';
  const profile  = d['Risk Profile'] || 'Moderate';
  if (!email) continue;

  const commentary = d.commentary || {};
  const niftyDir   = d.niftyDir   || 'flat';
  const comment    = (commentary[profile] || {})[niftyDir] || '';

  const needsAlert = parseFloat(d.niftyChange?.pct || 0) > 8;
  const alertBlock = needsAlert
    ? `<tr><td style="padding:0 40px 20px;"><div style="background:rgba(220,38,38,.08);border:1px solid rgba(220,38,38,.3);border-radius:12px;padding:16px 20px;"><div style="font-size:12px;color:#dc2626;font-weight:600;margin-bottom:6px;">⚠ Rebalancing Check Recommended</div><div style="font-size:13px;color:#5a6480;line-height:1.7;">NIFTY has moved significantly. Consider reviewing your ${profile} allocation.</div></div></td></tr>`
    : '';

  results.push({
    json: {
      flowType: 'weeklyPulse',
      name, email, profile, comment, alertBlock,
      weekDate:     d.weekDate,
      niftyPrice:   d.niftyPrice,
      niftyChange:  d.niftyChange,
      goldPrice:    d.goldPrice,
      goldChange:   d.goldChange,
      nasdaqPrice:  d.nasdaqPrice,
      nasdaqChange: d.nasdaqChange
    }
  });
}

return results.length ? results : [{ json: { flowType: 'weeklyPulse', skip: true } }];

// ── FLOW 3: Filter clients due for 6-month reassessment ──────
const now     = new Date();
const results = [];

for (const item of items) {
  const d     = item.json;
  const email = d['Email'] || '';
  const name  = d['Name']  || 'Investor';
  if (!email) continue;

  let submissionDate;
  try { submissionDate = new Date(d['Timestamp']); } catch { continue; }
  if (isNaN(submissionDate.getTime())) continue;

  const monthsDiff =
    (now.getFullYear() - submissionDate.getFullYear()) * 12 +
    (now.getMonth() - submissionDate.getMonth());

  // Fire at 6, 12, 18, 24... months
  if (monthsDiff <= 0 || monthsDiff % 6 !== 0) continue;

  const profile    = d['Risk Profile'] || 'Moderate';
  const cagr       = d['CAGR']         || '';
  const investment = d['Investment']   || '';
  const projection = d['Projection']   || '';

  const profileColors = { Conservative:'#0d9488', Moderate:'#b8860b', Aggressive:'#dc2626' };

  const originalDate = submissionDate.toLocaleDateString('en-IN', {
    day:'numeric', month:'long', year:'numeric'
  });

  const changesList = [
    'Your income or employment situation',
    'Your investment goals or target timeline',
    'Your risk tolerance after market movements',
    'Your overall financial obligations'
  ].map(c => `<li style="padding:4px 0;color:#5a6480;font-size:13px;">${c}</li>`).join('');

  results.push({
    json: {
      flowType: 'reassessment',
      name, email, profile, cagr, investment, projection,
      originalDate, monthsDiff,
      profileColor: profileColors[profile] || '#b8860b',
      changesList,
      formUrl: 'YOUR_VERCEL_FORM_URL_HERE',
      checkDate: now.toLocaleDateString('en-IN', { day:'numeric', month:'long', year:'numeric' })
    }
  });
}

return results.length ? results : [{ json: { flowType: 'reassessment', skip: true } }];
